class Solution:
    def countArrangement(self, n: int) -> int:
        used = [False] * (n + 1)
        def dfs(i):
            if i > n:
                return 1
            ans = 0
            for v in range(1, n + 1):
                if not used[v] and (i % v == 0 or v % i == 0):
                    used[v] = True
                    ans += dfs(i + 1)
                    used[v] = False
            return ans
        return dfs(1)

