class Solution {
    int n;
    vector<bool> used;
    int dfs(int i) {
        if (i > n) return 1;
        int ans = 0;
        for (int v = 1; v <= n; v++) {
            if (!used[v] && (i % v == 0 || v % i == 0)) {
                used[v] = true;
                ans += dfs(i + 1);
                used[v] = false;
            }
        }
        return ans;
    }
public:
    int countArrangement(int n) {
        this->n = n;
        used.assign(n + 1, false);
        return dfs(1);
    }
};
